// // This NOR gate outputs a high signal (1) when both inputs A and B are low (0)
module top_module(A, B, Y);specify             
    specparam tpdh = 15;
    specparam tpdl = 15;
    (A *> Y) = (tpdh, tpdl);
    (B *> Y) = (tpdh, tpdl);
  endspecify  
  input A;
  input B;
  output Y;

  assign Y = ~(A|B);endmodule
